let nextPay = "{{nextPay}}";
const country = "{{country}}";

nextPay = Date.parse(nextPay);
nextPay = new Date(nextPay);

// Set time zone and locale based on country
let timeZone;
if (country === 'AU') {
  timeZone = 'Australia/Sydney';
} else if (country === 'CA') {
  timeZone = 'America/Toronto';
} else {
  timeZone = 'America/New_York';
}

const now = new Date();
const formatter = new Intl.DateTimeFormat('en-US', {
    timeZone: timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: true, // Use false for 24-hour format
});

const date = new Date(formatter.format(now));

return date.getDate() === nextPay.getDate() &&
       (date.getMonth() + 1) === nextPay.getMonth() &&
       date.getFullYear() === nextPay.getFullYear();
